INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES (13020015, 11, 10, "いかんいかん\n資材の山に埋もれて\nしまうところだった", 302, "", "", "", 111031, "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES (13020016, 91, "", "", 302, "", "", "", 0, "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES (13020017, 3, 0, "nyx_302_yuni_02", 302, "", 0.2, 1, 2, "", "NoItem");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES (13020018, 3, 0, "nyx_302_yuni_02", 302, "", 0.2, 1, 111031, 0.2, "nyx_idle_normal");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES (13020019, 11, 10, "だが怪我の功名、\n探していた部品を\n偶然にも発見できた", 302, "", "", "", 111031, "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES (13020020, 93, "", "", 302, "", "", "", 5, "", "");
