INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES (13020022, 3, 1, "nyx_cmn_03", 302, "", 0.2, "", 111031, "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES (13020023, 11, 10, "ふむ…これは僥倖\nかくなる上は再び\n潜航してみるか…", 302, "", "", "", 111031, "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES (13020024, 91, "", "", 302, "", "", "", 0, "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES (13020025, 3, 1, "nyx_301_yuni_01", 302, "", 0.2, "", 111031, "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES (13020026, 11, 10, "存外意義あるものだ\n資材ダイビングとか\nいう新種の探索行は", 302, "", "", "", 111031, "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES (13020027, 91, "", 1, 302, "", "", "", 0, "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES (13020028, 11, 10, "まあ万一溺れたとて\n後輩たちの誰ぞが\nきっと気付くだろう", 302, "", "", "", 111031, "", "");
INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES (13020029, 91, "", 1, 302, "", "", "", 0, "", "");
