INSERT INTO `v1_8d72aef7fe32ce752c9f65c42701afcf8f956a769399d5cba2d592d1203dea9c` VALUES (13020034, 11, 10, "む。奥に入りすぎた\nこれは…出られぬ！\n誰かー！　誰か―！", 302, "", "", "", 111031, "", "");
